mapper.update:
UPDATE RSN_RELEASE_UNIT
SET RELEASE_STATUS = #{releaseStatus},
    UPDATED_AT = #{updatedAt, typeHandler=egovframework.com.config.data.CubridLocalDateTimeTypeHandler}
WHERE RELEASE_UNIT_ID = #{releaseUnitId}

UPDATE RSN_DEPLOY_TRACE
SET DEPLOY_STATUS = #{deployStatus},
    DEPLOY_LOG = #{deployLog},
    FINISHED_AT = #{finishedAt, typeHandler=egovframework.com.config.data.CubridLocalDateTimeTypeHandler},
    UPDATED_AT = #{finishedAt, typeHandler=egovframework.com.config.data.CubridLocalDateTimeTypeHandler}
WHERE DEPLOY_TRACE_ID = #{deployTraceId}

mapper.select:
SELECT * FROM RSN_DEPLOY_TRACE
WHERE RUNTIME_PACKAGE_ID = #{runtimePackageId}
  AND TARGET_ENV = #{targetEnv}
ORDER BY STARTED_AT DESC
LIMIT 1
